userDefinedLinkHintCss:
/* Vimium Theme: Rose Pine Moon — Solid, shadow-free */

/* ---------- Reset ---------- */
#vomnibar,
#vomnibar input,
#vomnibar li,
.vimiumHintMarker {
  font-family: "Inter", "SF Pro Text", system-ui, sans-serif !important;
  -webkit-font-smoothing: antialiased !important;
  box-sizing: border-box !important;
}

/* ---------- Vomnibar container ---------- */
#vomnibar {
  background: #232136 !important;
  border: 2px solid #393552 !important;
  border-radius: 12px !important;
  padding: 0 !important;
  width: 860px !important;
  max-width: 54vw !important;
  max-height: calc(100vh - 80px) !important;
  overflow: hidden !important;
  box-shadow: none !important;
}

/* ---------- Search area ---------- */
#vomnibar #vomnibar-search-area {
  background: transparent !important;
  border: none !important;
  padding: 0 !important;
  margin: 0 !important;
}

#vomnibar input {
  width: 100% !important;
  margin: 0 !important;
  padding: 20px 20px !important;
  border: none !important;
  border-bottom: 1px solid #393552 !important;
  border-radius: 0 !important;
  background: #2a273f !important;
  color: #e0def4 !important;
  font-size: 17px !important;
  font-weight: 500 !important;
  line-height: 1.5 !important;
  letter-spacing: 0.01em !important;
  box-shadow: none !important;
  outline: none !important;
}

/* ---------- Results list ---------- */
#vomnibar ul {
  margin: 0 !important;
  padding: 4px 0 !important;
  list-style: none !important;
  background: transparent !important;
  border: none !important;
}

#vomnibar li {
  margin: 0 !important;
  padding: 12px 20px !important;
  border: none !important;
  border-radius: 0 !important;
  background: transparent !important;
  border-left: 3px solid transparent !important;
}

#vomnibar li + li {
  border-top: 1px solid rgba(57, 53, 82, 0.5) !important;
}

#vomnibar li.selected {
  background: #2a273f !important;
  border-left-color: #c4a7e7 !important;
}

/* ---------- Result row layout ---------- */
#vomnibar li .top-half,
#vomnibar li .bottom-half {
  padding: 0 !important;
  display: flex !important;
  align-items: baseline !important;
  gap: 12px !important;
  line-height: 1.5 !important;
}

#vomnibar li .top-half {
  margin-bottom: 3px !important;
}

/* Source badge */
#vomnibar li .source {
  display: inline-block !important;
  width: auto !important;
  min-width: 52px !important;
  flex-shrink: 0 !important;
  padding: 1px 8px !important;
  border-radius: 4px !important;
  background: #393552 !important;
  color: #f6c177 !important;
  font-size: 10px !important;
  font-weight: 700 !important;
  letter-spacing: 0.06em !important;
  text-transform: uppercase !important;
  text-align: center !important;
  line-height: 1.8 !important;
}

/* Title */
#vomnibar li .title {
  color: #e0def4 !important;
  font-size: 13.5px !important;
  font-weight: 500 !important;
  line-height: 1.5 !important;
  white-space: nowrap !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;
}

/* URL */
#vomnibar li .url {
  color: #6e6a86 !important;
  font-size: 11.5px !important;
  font-weight: 400 !important;
  padding-left: 0 !important;
  margin-left: 72px !important;
  white-space: nowrap !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;
  line-height: 1.5 !important;
}

/* Match highlight */
#vomnibar li .match {
  color: #ea9a97 !important;
  font-weight: 700 !important;
  text-decoration: none !important;
}

/* Selected row overrides */
#vomnibar li.selected .title {
  color: #9ccfd8 !important;
}

#vomnibar li.selected .url {
  color: #908caa !important;
}

#vomnibar li.selected .source {
  background: #c4a7e7 !important;
  color: #232136 !important;
}

/* ---------- Link hints ---------- */
#vimium-hint-marker-container div.internal-vimium-hint-marker,
#vimium-hint-marker-container div.vimiumHintMarker {
  background: #f6c177 !important;
  border: 2px solid #232136 !important;
  border-radius: 4px !important;
  padding: 2px 6px !important;
  box-shadow: none !important;
}

#vimium-hint-marker-container div span {
  color: #232136 !important;
  font-size: 12px !important;
  font-weight: 800 !important;
  text-shadow: none !important;
}

#vimium-hint-marker-container div span.matchingCharacter {
  color: #eb6f92 !important;
}

/* ---------- Find HUD ---------- */
div#hud-container {
  background: #232136 !important;
  border: 2px solid #393552 !important;
  border-radius: 8px !important;
  box-shadow: none !important;
}

div#hud-container span#hud-find-input,
div#hud-container div#hud {
  color: #e0def4 !important;
}

div#hud-container .hud-find,
div#hud-container #search-area {
  background: #232136 !important;
}

/* ---------- Settings page ---------- */
body.vimium-body,
body.vimium-body header,
body.vimium-body label {
  background: #232136 !important;
  color: #e0def4 !important;
}

body.vimium-body a {
  color: #c4a7e7 !important;
}

body.vimium-body button,
body.vimium-body footer,
body.vimium-body textarea,
body.vimium-body input {
  background: #2a273f !important;
  color: #e0def4 !important;
  border: 1px solid #393552 !important;
  border-radius: 6px !important;
  scrollbar-color: #908caa #2a273f !important;
}

body.vimium-body #wrapper .example {
  color: #908caa !important;
}

body.vimium-body button:focus,
body.vimium-body input:focus,
body.vimium-body textarea:focus {
  border-color: #c4a7e7 !important;
  outline: none !important;
}

/* ---------- Help dialog ---------- */
#dialog {
  background: #232136 !important;
  color: #e0def4 !important;
  border: 2px solid #393552 !important;
  border-radius: 10px !important;
  box-shadow: none !important;
}

#dialog .divider {
  background: #393552 !important;
}

#dialog a,
#dialog span.vim {
  color: #9ccfd8 !important;
}

#dialog h1,
#dialog h2,
#dialog div.help-description,
#dialog a#close {
  color: #e0def4 !important;
}

#dialog a#close:hover {
  color: #ea9a97 !important;
}

#dialog .key,
body.vimium-body .key {
  background: #2a273f !important;
  color: #e0def4 !important;
  border: 1px solid #393552 !important;
  border-radius: 4px !important;
  padding: 2px 7px !important;
}

/* ---------- Visual selection ---------- */
::selection {
  background: #c4a7e7 !important;
  color: #232136 !important;
}

/* ---------- Responsive: narrower browser window ---------- */
@media (max-width: 1100px) {
  #vomnibar {
    max-width: 88vw !important;
  }

  #vomnibar input {
    font-size: 15px !important;
    padding: 16px 16px !important;
  }

  #vomnibar li {
    padding: 10px 16px !important;
  }

  #vomnibar li .source {
    min-width: 46px !important;
    font-size: 9px !important;
    padding: 1px 6px !important;
  }

  #vomnibar li .title {
    font-size: 13px !important;
  }

  #vomnibar li .url {
    font-size: 11px !important;
    margin-left: 64px !important;
  }
}
